import UIKit
import WebKit

class ViewController: UIViewController {
    let webView = WKWebView()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Load mobile website into the WebView
        guard let url = URL(string: "https://your-mobile-website.com") else { return }
        webView.load(URLRequest(url: url))
        
        // Enable JavaScript for full web app functionality
        webView.configuration.userContentController.add(self, name: "nativeCall")
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        switch message.body as? String {
        case "cameraAccess":
            // Handle camera access request from web content
            print("Camera access requested")
        case "pushNotifications":
            // Handle push notifications request from web content
            print("Push notifications requested")
        case "inAppPurchase":
            // Handle in-app purchase request from web content
            print("In-app purchase requested")
        default:
            print("Unknown message received: \(message.body)")
        }
    }
}

extension ViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        if let url = navigationAction.request.url?.absoluteString {
            // Restrict loaded origins
            guard url.hasPrefix("https://your-mobile-website.com") else { return }
            
            decisionHandler(.allow)
        } else {
            decisionHandler(.cancel)
        }
    }
    
    func webView(_ webView: WKWebView, didReceiveServerRedirectForProvisionalNavigationFrom response: URLResponse) {
        // Validate all web-to-native messages
        guard let message = response.url?.query else { return }
        
        if let body = try? JSONSerialization.jsonObject(with: Data(message.utf8), options: []) as? [String: Any] {
            // Check for valid native call
            if let type = body["type"] as? String, type == "nativeCall" {
                userContentController(webView.configuration.userContentController, didReceive: WKScriptMessage(body: message))
            }
        }
    }
